const GEO_CONFIG={API_URL:'https://ipapi.co/json/',CACHE_KEY:'geo-location-cache',CACHE_DURATION:24*60*60*1e3,DEFAULT_LOCATION:{Tunisia:{cities:'Tunis, Sfax, Sousse',country:'Tunisia',countryCode:'TN',latitude:'36.8065',longitude:'10.1815'},France:{cities:'Paris, Lyon, Marseille',country:'France',countryCode:'FR',latitude:'48.8566',longitude:'2.3522'}}};async function fetchWithTimeout(e,t= {},n=5e3){const r=new AbortController,i=setTimeout(()=>r.abort(),n);try{const o=await fetch(e,Object.assign({},t,{signal:r.signal}));return clearTimeout(i),o}catch(e){clearTimeout(i);throw e}}async function fetchUserLocation(){const maxRetries=2;let attempt=0,backoff=1e3;try{const failed=localStorage.getItem('geo-failure');if(failed){const data=JSON.parse(failed);if(data&&data.expires&&Date.now()<data.expires){console.warn('GEO: Recently failed API call; using fallback until',new Date(data.expires).toISOString());return null}else localStorage.removeItem('geo-failure')}}catch(e){}while(attempt<=maxRetries)try{const response=await fetchWithTimeout(GEO_CONFIG.API_URL,{method:'GET',headers:{Accept:'application/json'}},5e3);if(429===response.status){const retryAfter=response.headers.get('Retry-After'),wait=retryAfter?parseInt(retryAfter,10)*1e3:6e4;try{localStorage.setItem('geo-failure',JSON.stringify({expires:Date.now()+wait}))}catch(e){}throw new Error('API rate limited (429)')}if(!response.ok)throw new Error('API Error: '+response.status);const data=await response.json();return{city:data.city||'',country:data.country_name||'',countryCode:data.country_code||'',region:data.region||'',latitude:data.latitude||'',longitude:data.longitude||'',timezone:data.timezone||''}}catch(error){if(attempt===maxRetries){console.warn('GEO: Location API fetch failed after retries',error);try{localStorage.setItem('geo-failure',JSON.stringify({expires:Date.now()+3e4}))}catch(e){}return null}await new Promise(e=>setTimeout(e,backoff));backoff*=2;attempt++}return null}function getCachedLocation(){try{const cached=localStorage.getItem(GEO_CONFIG.CACHE_KEY);if(!cached)return null;const{data,timestamp}=JSON.parse(cached);const isExpired=Date.now()-timestamp>GEO_CONFIG.CACHE_DURATION;if(isExpired){try{localStorage.removeItem(GEO_CONFIG.CACHE_KEY)}catch(e){}return null}return data}catch(error){console.warn('GEO: Cache retrieval failed',error);window.GEO_STORAGE_AVAILABLE=false;return null}}function setCachedLocation(t){if(window.GEO_STORAGE_AVAILABLE===false)return;try{const e={data:t,timestamp:Date.now()};localStorage.setItem(GEO_CONFIG.CACHE_KEY,JSON.stringify(e))}catch(error){console.warn('GEO: Cache save failed',error);if(error&&(error.name==='QuotaExceededError'||error.name==='NS_ERROR_DOM_QUOTA_REACHED')){window.GEO_STORAGE_AVAILABLE=false;try{localStorage.removeItem(GEO_CONFIG.CACHE_KEY)}catch(e){}}}}function formatLocationString(e){if(!e)return'';if(e.city&&e.city.trim())return e.city.trim();if(e.region&&e.region.trim())return e.region.trim();return e.country||''}function getLocalizedMessage(e,t){const n={TN:{text:'Tunis, Sfax, Sousse',greeting:'Salam from Tunisia! 🇹🇳',note:'Serving Tunisian businesses and startups.'},FR:{text:'Paris, Lyon, Marseille',greeting:'Bienvenue from France! 🇫🇷',note:'RGPD-aware solutions for French businesses.'},US:{text:'United States',greeting:'Hello from the US! 🇺🇸'}};const r={'Tunis':{greeting:'Salam from Tunis! 🇹🇳'},'Sfax':{greeting:'Greetings from Sfax! 🇹🇳'},'Sousse':{greeting:'Hello from Sousse! 🇹🇳'},'Paris':{greeting:'Bonjour from Paris! 🇫🇷'},'Lyon':{greeting:'Salut from Lyon! 🇫🇷'},'Marseille':{greeting:'Bonjour from Marseille! 🇫🇷'}};if(t&&r[t])return Object.assign({},n[e]||{},r[t]);return n[e]||{text:'worldwide',greeting:'Hello! 👋'}}function updateGeoTargets(e){const t=document.querySelectorAll('.geo-target');if(!t.length){console.log('GEO: No .geo-target elements found on page');return}const n=getLocalizedMessage(e&&e.countryCode,e&&e.city);const r=formatLocationString(e);const o=(r&&r.trim())||(n&&n.text)||'worldwide';let statusEl=document.getElementById('geo-status');if(!statusEl){statusEl=document.createElement('div');statusEl.id='geo-status';statusEl.setAttribute('aria-live','polite');statusEl.style.position='absolute';statusEl.style.left='-9999px';statusEl.style.width='1px';statusEl.style.height='1px';statusEl.style.overflow='hidden';document.body.appendChild(statusEl)}if(n&&n.greeting)console.log('GEO:',n.greeting);t.forEach(function(t){t.setAttribute('aria-live','polite');t.style.opacity='0.7';t.style.transition='all .3s ease-in-out';setTimeout(function(){t.textContent=o||'worldwide';t.style.opacity='1'},150)});if(n&&n.note)statusEl.textContent=n.note;else statusEl.textContent='';console.log('GEO: Location detected -',{city:e&&e.city,country:e&&e.country,countryCode:e&&e.countryCode,region:e&&e.region})}async function initGeoTargeting(){try{const e=document.querySelectorAll('.geo-target');if(!e.length){console.log('GEO: Page has no .geo-target elements');return}console.log('GEO: Initializing geolocation system...');if(!document.getElementById('geo-status')){const t=document.createElement('div');t.id='geo-status';t.setAttribute('aria-live','polite');t.style.position='absolute';t.style.left='-9999px';t.style.width='1px';t.style.height='1px';t.style.overflow='hidden';document.body.appendChild(t)}let location=getCachedLocation();if(!location){console.log('GEO: No cached location, fetching from API...');location=await fetchUserLocation();if(location){setCachedLocation(location);console.log('GEO: Location cached for 24 hours')}else{console.warn('GEO: API failed; using conservative defaults');const sample=document.querySelector('.geo-target');const hint=sample?sample.textContent.trim():'';if(hint&&GEO_CONFIG.DEFAULT_LOCATION[hint]){location=Object.assign({},GEO_CONFIG.DEFAULT_LOCATION[hint],{city:''});document.getElementById('geo-status').textContent=`Location set to ${hint} by page hint.`}else{const path=window.location.pathname.toLowerCase();if(path.includes('tunisia')){location=Object.assign({},GEO_CONFIG.DEFAULT_LOCATION.Tunisia);document.getElementById('geo-status').textContent='Defaulted to Tunisia based on page URL.'}else if(path.includes('france')){location=Object.assign({},GEO_CONFIG.DEFAULT_LOCATION.France);document.getElementById('geo-status').textContent='Defaulted to France based on page URL.'}else{location={city:'',region:'',country:'',countryCode:''};document.getElementById('geo-status').textContent='Location not detected; showing global services.'}}}}else console.log('GEO: Using cached location');if(location&&(location.countryCode||location.city||location.country))updateGeoTargets(location);else{updateGeoTargets({city:'',region:'',country:'',countryCode:''});console.warn('GEO: Could not determine user location; using generic fallback')}}catch(error){console.error('GEO: Initialization failed',error);try{const status=document.getElementById('geo-status');if(status)status.textContent='Geolocation service unavailable at the moment.'}catch(e){}}}window.GEO_FORCE_UPDATE=async function(){try{console.log('GEO: Forcing location update...');try{localStorage.removeItem(GEO_CONFIG.CACHE_KEY)}catch(e){}await initGeoTargeting()}catch(e){console.error('GEO_FORCE_UPDATE failed:',e)}};window.GEO_CLEAR_CACHE=function(){try{try{localStorage.removeItem(GEO_CONFIG.CACHE_KEY)}catch(e){}console.log('GEO: Cache cleared')}catch(e){console.warn('GEO_CLEAR_CACHE could not clear cache:',e)}};window.GEO_GET_CACHED=function(){try{return getCachedLocation()}catch(err){console.warn('GEO_GET_CACHED failed:',err);return null}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initGeoTargeting)}else initGeoTargeting();